'use client';

import { useState } from 'react';
import { Search, Filter, MoreHorizontal, GraduationCap, Eye, Edit, Mail, Award, Calendar, ChevronRight } from 'lucide-react';
import Link from 'next/link';
import { UserProfile } from '@/src/lib/types/users_turmas';
import { motion, AnimatePresence } from 'framer-motion';

interface AlunosListProps {
    alunos: UserProfile[];
}

export function AlunosList({ alunos }: AlunosListProps) {
    const [searchTerm, setSearchTerm] = useState('');
    const [filterNivel, setFilterNivel] = useState('todos');

    const filteredAlunos = alunos.filter(aluno => {
        const matchesSearch = (aluno.full_name?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
            (aluno.email?.toLowerCase() || '').includes(searchTerm.toLowerCase());

        // Simulação de filtro de nível (assumindo que nivel_atual existe ou vamos mockar se for null)
        const nivel = (aluno as any).nivel_atual || 'iniciante';
        const matchesFilter = filterNivel === 'todos' || nivel.toLowerCase() === filterNivel.toLowerCase();

        return matchesSearch && matchesFilter;
    });

    const container = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: {
                staggerChildren: 0.05
            }
        }
    };

    const item = {
        hidden: { opacity: 0, y: 10 },
        show: { opacity: 1, y: 0 }
    };

    return (
        <div className="space-y-6">
            {/* Toolbar */}
            <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex flex-col sm:flex-row gap-4 justify-between bg-white p-4 rounded-xl shadow-sm border border-gray-100"
            >
                <div className="relative flex-1 group">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5 group-focus-within:text-purple-600 transition-colors" />
                    <input
                        type="text"
                        placeholder="Buscar aluno por nome ou email..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 rounded-lg border border-gray-200 focus:ring-2 focus:ring-purple-500 focus:border-purple-500 outline-none transition-all bg-gray-50 focus:bg-white"
                    />
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                    <div className="relative">
                        <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
                        <select
                            value={filterNivel}
                            onChange={(e) => setFilterNivel(e.target.value)}
                            className="pl-10 pr-8 py-2.5 rounded-lg border border-gray-200 bg-white text-gray-700 outline-none focus:ring-2 focus:ring-purple-500 cursor-pointer appearance-none hover:bg-gray-50 transition-colors"
                        >
                            <option value="todos">Todos os Níveis</option>
                            <option value="iniciante">Iniciante</option>
                            <option value="intermediário">Intermediário</option>
                            <option value="avançado">Avançado</option>
                        </select>
                    </div>

                    <Link
                        href="/admin/alunos/novo"
                        className="flex-1 sm:flex-none justify-center inline-flex items-center gap-2 bg-gradient-to-r from-purple-600 to-indigo-600 hover:from-purple-700 hover:to-indigo-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all shadow-md shadow-purple-200 active:scale-95"
                    >
                        <Plus className="w-5 h-5" />
                        Novo Aluno
                    </Link>
                </div>
            </motion.div>

            {/* Content */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                        <thead className="bg-gray-50/50 text-gray-900 font-semibold border-b border-gray-200">
                            <tr>
                                <th className="px-6 py-4">Aluno</th>
                                <th className="px-6 py-4">Contato</th>
                                <th className="px-6 py-4">Status Acadêmico</th>
                                <th className="px-6 py-4">Matrícula</th>
                                <th className="px-6 py-4 text-right">Ações</th>
                            </tr>
                        </thead>
                        <motion.tbody
                            variants={container}
                            initial="hidden"
                            animate="show"
                            className="divide-y divide-gray-100"
                        >
                            <AnimatePresence>
                                {filteredAlunos.length > 0 ? (
                                    filteredAlunos.map((aluno: any) => (
                                        <motion.tr
                                            key={aluno.id}
                                            variants={item}
                                            layout
                                            className="hover:bg-purple-50/30 transition-colors group"
                                        >
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-purple-100 to-indigo-100 flex items-center justify-center text-purple-700 font-bold shadow-sm border-2 border-white ring-2 ring-gray-50 group-hover:ring-purple-100 transition-all">
                                                        {aluno.avatar_url ? (
                                                            <img src={aluno.avatar_url} alt="" className="w-full h-full object-cover rounded-full" />
                                                        ) : (
                                                            aluno.full_name?.charAt(0) || 'A'
                                                        )}
                                                    </div>
                                                    <div>
                                                        <div className="font-bold text-gray-900 group-hover:text-purple-700 transition-colors">{aluno.full_name}</div>
                                                        <div className="text-xs text-gray-500 flex items-center gap-1 font-medium">
                                                            <Calendar className="w-3 h-3" />
                                                            Membro desde {new Date(aluno.created_at || Date.now()).toLocaleDateString('pt-BR')}
                                                        </div>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-2 text-gray-600 group-hover:text-gray-900 transition-colors">
                                                    <Mail className="w-4 h-4 text-gray-400 group-hover:text-purple-400" />
                                                    {aluno.email}
                                                </div>
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex flex-col gap-1">
                                                    <span className={`inline-flex items-center w-fit px-2.5 py-0.5 rounded-full text-xs font-bold border ${(aluno.nivel_atual || 'iniciante') === 'avançado' ? 'bg-purple-50 text-purple-700 border-purple-100' :
                                                        (aluno.nivel_atual || 'iniciante') === 'intermediário' ? 'bg-blue-50 text-blue-700 border-blue-100' :
                                                            'bg-green-50 text-green-700 border-green-100'
                                                        }`}>
                                                        <Award className="w-3 h-3 mr-1" />
                                                        {(aluno.nivel_atual || 'Iniciante').charAt(0).toUpperCase() + (aluno.nivel_atual || 'iniciante').slice(1)}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 font-mono text-sm text-gray-500 font-medium tracking-wide">
                                                #{aluno.matricula || '---'}
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0">
                                                    <Link
                                                        href={`/admin/alunos/${aluno.id}`}
                                                        className="p-2 text-gray-400 hover:text-purple-600 hover:bg-purple-50 rounded-lg transition-colors border border-transparent hover:border-purple-100"
                                                        title="Ver Perfil Detalhado"
                                                    >
                                                        <Eye className="w-4 h-4" />
                                                    </Link>
                                                    <Link
                                                        href={`/admin/alunos/${aluno.id}`}
                                                        className="p-2 text-gray-400 hover:text-purple-600 hover:bg-purple-50 rounded-lg transition-colors border border-transparent hover:border-purple-100"
                                                        title="Ver Detalhes"
                                                    >
                                                        <ChevronRight className="w-4 h-4" />
                                                    </Link>
                                                </div>
                                            </td>
                                        </motion.tr>
                                    ))
                                ) : (
                                    <tr>
                                        <td colSpan={5} className="px-6 py-16 text-center text-gray-500 bg-white">
                                            <motion.div
                                                initial={{ scale: 0.9, opacity: 0 }}
                                                animate={{ scale: 1, opacity: 1 }}
                                                className="flex flex-col items-center justify-center gap-4"
                                            >
                                                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center border border-gray-100">
                                                    <Search className="w-8 h-8 text-gray-300" />
                                                </div>
                                                <div>
                                                    <p className="font-bold text-gray-900 text-lg">Nenhum aluno encontrado</p>
                                                    <p className="text-sm text-gray-500 mt-1">Tente ajustar seus filtros de busca.</p>
                                                </div>
                                            </motion.div>
                                        </td>
                                    </tr>
                                )}
                            </AnimatePresence>
                        </motion.tbody>
                    </table>
                </div>
                <div className="px-6 py-4 border-t border-gray-200 bg-gray-50/50 text-xs text-gray-500 flex justify-between items-center font-medium">
                    <span>Mostrando <span className="text-gray-900 font-bold">{filteredAlunos.length}</span> de {alunos.length} alunos</span>
                    {/* Placeholder for future pagination */}
                    <div className="flex gap-1">
                        <button className="px-3 py-1 bg-white border border-gray-200 rounded-md hover:bg-gray-50 disabled:opacity-50" disabled>Anterior</button>
                        <button className="px-3 py-1 bg-white border border-gray-200 rounded-md hover:bg-gray-50 disabled:opacity-50" disabled>Próxima</button>
                    </div>
                </div>
            </div>
        </div>
    );
}
